import React, { useState } from "react";
import { Mic } from "lucide-react";
import { aiAPI } from "../services/api";

export default function VoiceAdvisor() {
  const [listening, setListening] = useState(false);
  const [response, setResponse] = useState("");

  const startListening = () => {
    const recognition = new window.webkitSpeechRecognition();
    recognition.lang = "en-US";

    recognition.start();
    setListening(true);

    recognition.onresult = async (event) => {
      const transcript = event.results[0][0].transcript;
      setListening(false);

      try {
        const res = await aiAPI.voiceAdvisor({ query: transcript });
        const reply = res.data.response;

        setResponse(reply);

        // 🔊 Speak response
        const speech = new SpeechSynthesisUtterance(reply);
        window.speechSynthesis.speak(speech);

      } catch (err) {
        setResponse("Error getting AI response");
      }
    };
  };

  return (
    <div className="p-6 rounded-xl bg-white/5 border border-white/10 mt-6">
      <h2 className="text-lg font-bold mb-4">🎤 Voice Career Advisor</h2>

      <button
        onClick={startListening}
        className="px-4 py-2 bg-purple-500 rounded flex items-center gap-2"
      >
        <Mic size={16} />
        {listening ? "Listening..." : "Ask by Voice"}
      </button>

      {response && (
        <p className="mt-4 text-white/80">{response}</p>
      )}
    </div>
  );
}
